INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0, 2, 0, "お！\nあそこに困ってそうな人発見！", 1001, "春咲 ひより", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "わ、わたし、\nなに言ってるんだろ\nあはは…", "みんなみたいに\nわたしも強くならなきゃ", 0, 2, 0, "大切な人を\n守れるようになりたい…って", 1002, "草野 優衣", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "少しは磨かれると思いますよ。", "フェンシングを始めてみては？", 0, 2, 0, "キミに必要な集中力と感性が", 1003, "士条 怜", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "みそぎはねぇ、\nかくれんぼやりたい！", "ねぇ、にいちゃん！", 0, 2, 0, "今日はなにして遊ぶ？", 1004, "穂高 みそぎ", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "私といっしょに…\nいかない？", "風宮あかりです", 0, 2, 0, "ねぇ…", 1006, "風宮 あかり", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "食べ物の恨みは怖いのー", "出雲宮子なのー", 0, 2, 0, "プリンたべたいのー", 1007, "出雲 宮子", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "いいよ。\n見られることは運命さ…", "ボクは虹村雪。", 0, 2, 0, "キミもボクの美貌に\n吸い寄せられたんだね。", 1008, "虹村 雪", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "人呼んで「疾風の冥姫」!!", "フッ…聞いて後悔するがいい！", 0, 2, 0, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1009, "柊杏奈", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "ほんまおおきにやわ～♪", "マホマホ王国のプリンセス、\nまほ姫どす", 0, 2, 0, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1010, "姫宮 真歩", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "ここで会ったが\n100年目～！", "衣之咲璃乃です！", 0, 2, 0, "生き別れたお兄ちゃんを探して\n三千世界！", 1011, "衣之咲 璃乃", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "…って、お願い！\n誰にも言わないでおいて～！", "私はハツネ、\n結構強いんだよ。\nきらーん☆", 0, 2, 0, "ち、超能力って…\n何のことかな～？", 1012, "柏崎 初音", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", "ちょす！\n美波鈴奈だよ～♪", 0, 2, 0, "一応カリスマ読モJKやってまっす！", 1016, "美波 鈴奈", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "でも、沖縄もとってもいいとこさー", "はいたーい。\n喜屋武香織さー。", 0, 2, 0, "東京は遊園地みたいなところさー", 1017, "喜屋武 香織", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "イオちゃんって呼んでね。", "支倉伊緒です。", 0, 2, 0, "先生って呼ばれるのは\nくすぐったいから", 1018, "支倉 伊緒", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "ミミをおいてかないでぇ～", "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0, 2, 0, "あ！/\お兄ちゃ～ん\nまってよ～", 1020, "茜 ミミ", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "ふぇぇぇぇぇん……", "あ…あの…えっと…\n栗…林…くるみ…です……", 0, 2, 0, "あの……\nふぇ……", 1021, "栗林 くるみ", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "なんてありがとうございます！", "風宮よりです。\nあああああ！", 0, 2, 0, "こんな私に貴重な時間を\n割いていただき、", 1022, "風宮 より", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "私こっち行きたいー\nね、早く早くー", "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0, 2, 0, "おにいちゃんどこいくの？\nえ？", 1023, "北条 綾音", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "これて何か違う…\nあああすみません！", "わっ…わっ…私、\n天野すずめといいます！", 0, 2, 0, "ふ、不束者ですが\nどうぞ末永く…って、", 1025, "天野 すずめ", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "離しませんわ………\n絶対に…!!", "……クスクス…私は\n…倉石恵理子……", 0, 2, 0, "あなたは…運命の……\n伴侶……", 1027, "倉石 恵理子", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "…そうでしょ？？", "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0, 2, 0, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1028, "佐々木 咲恋", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "あはは、\n私もまだまだだなぁ～", "桜井望だよ！\nよろしくねっ", 0, 2, 0, "ぇっと…\nキミ、私のこと知らないの?!", 1029, "桜井 望", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "ショーグン、\nワタシと一緒に天下統一デース！", "デケデケデンっ！", 0, 2, 0, "初めまして、\n私はニノン・ジュベール申すデス！", 1030, "ニノン・ジュベール", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "おかしいですね……", "上喜しのぶです。\n手元のドクロが父です。", 0, 2, 0, "でもって私の隣にいるのが……\nえ、見えない？", 1031, "上喜 しのぶ", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "そう、\nオラのボケに突っ込める相方が…！", "目指すはビッグな\nお笑い芸人だっぺ！", 0, 2, 0, "けんども\nそれには足りないモンが…", 1033, "野戸まひる", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "ちょ\nちょっと一杯飲んできます…！", "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0, 2, 0, "ちょっと緊張しちゃって…", 1034, "綾瀬 ゆかり", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "これ以上お話しすることは…\nないです！", "氷川鏡華…です", 0, 2, 0, "知らない人とは話しちゃいけないので", 1036, "氷川 鏡華", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", "柏崎…栞です。", 0, 2, 0, "……あ、アラーム。", 1038, "柏崎 栞", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "野に咲く花が、\n唯一の話相手です。", "ふ、双葉碧です。", 0, 2, 0, "私、一人も友達がいなくて……", 1040, "双葉 碧", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "そう思っています。", "三角千歌です。", 0, 2, 0, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1042, "三角 千歌", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "う、疑ってすまなかったな…", "安芸真琴だ。", 0, 2, 0, "あぁ？\nお前のそいつの仲間か？", 1043, "安芸 真琴", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", "わらわこそは夜を総べる者！", 0, 2, 0, "生けとし生ける全ての者よ！", 1044, "イリヤ・オーンスタイン", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "ｌク、クウカに何かご用ですか!?", "そこで騎士は妖精を乱暴に……", 0, 2, 0, "ぐふふふふ……はっ！", 1045, "遠見 空花", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "う～ん…\n猫ってホントに最高にゃ～♪", "宮坂たまきにゃ♪\n猫はいいにゃよ？", 0, 2, 0, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1046, "宮坂たまき", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "…と思ったら\nバイトの時間だ！\nまたあとでね！", "大神美冬よ！", 0, 2, 0, "それでは早速クエストに…", 1048, "大神 美冬", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", "星野静流だよ！", 0, 2, 0, "クエストもバトルも\n掃除も洗濯も", 1049, "星野静流", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", "アタシは玉泉美咲。", 0, 2, 0, "見ての通りの\nセクシー美少女で", 1050, "玉泉美咲", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "？？？？", "？？？", 0, 2, 0, "？？？？", 1052, "リマ", 0, 1.4);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "そ、そこまでいうなら\nもらってやる", "モニカ・ヴァイスヴィントだ。", 0, 2, 0, "菓子でつろうなどと\n稚拙な策を……", 1053, "モニカ・ヴァイスヴィント", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "そ、そこまでいうなら\nもらってやる", "モニカ・ヴァイスヴィントだ。", 0, 2, 0, "菓子でつろうなどと\n稚拙な策を……", 1058, "ペコリーヌ", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "そ、そこまでいうなら\nもらってやる", "モニカ・ヴァイスヴィントだ。", 0, 2, 0, "菓子でつろうなどと\n稚拙な策を……", 1059, "コッコロ", 0, 1.5);
INSERT INTO `v1_b7573d32ae9d58a407bef1cdfce407d0c3832d10c415b5396267ce71e56a6b92` VALUES (0, 0, 1, 1, 1, "そ、そこまでいうなら\nもらってやる", "モニカ・ヴァイスヴィントだ。", 0, 2, 0, "菓子でつろうなどと\n稚拙な策を……", 1060, "キャル", 0, 1.5);
